import React from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { ArrowLeft, Github, Layers } from 'lucide-react';

const AllProjects = () => {
  const navigate = useNavigate();

  const projects = [
    {
      title: "Multi-Tenant SaaS Healthcare Platform",
      category: "Backend Architecture",
      image: "img/project-1.png",
      description: "Architected a centralized multi-tenant SaaS backend using ASP.NET Core serving 7 integrated applications with strict tenant isolation. Engineered 200+ RESTful API endpoints secured with JWT and RBAC. Optimized a PostgreSQL database with strategic indexing. Integrated Lemon Squeezy for automated global billing and developed asynchronous background services via webhook integrations.",
      tags: ["ASP.NET Core", "PostgreSQL", "JWT", "RBAC", "Lemon Squeezy", "Webhooks"],
      live: "#",
      github: "#"
    },
    {
      title: "SaaS Administrative Ecosystem",
      category: "Frontend Web Application",
      image: "img/project-2.png",
      description: "Fully developed an administrative dashboard using Next.js to manage medical users, appointments, and configurations. Implemented Next.js Middleware for server-side authentication and protected routing. Designed responsive UI components and utilized React Context API for consistent global state synchronization.",
      tags: ["Next.js", "React Context API", "Middleware", "UI/UX", "Tailwind CSS"],
      live: "#",
      github: "#"
    },
    {
      title: "Real-time Affiliate & Partner Management",
      category: "Full-Stack Web Application",
      image: "img/project-3.png",
      description: "Developed a complete partner ecosystem using Vue.js and ASP.NET Core for healthcare provider onboarding and real-time revenue tracking. Engineered a revenue tracking engine using Webhooks and SignalR for zero-latency financial updates. Implemented Pinia for high-performance state management of complex real-time data streams.",
      tags: ["Vue.js", "ASP.NET Core", "SignalR", "Pinia", "Webhooks"],
      live: "#",
      github: "#"
    },
    {
      title: "AI-Powered Smart Content Platform",
      category: "AI/Backend Integration",
      image: "img/project-4.png",
      description: "Developed high-performance REST APIs using FastAPI bridging LLM-based AI models and the frontend. Engineered an asynchronous task queue system using Celery and Redis to handle long-running AI operations. Built secure registration flows and an administrative Next.js dashboard for system configurations.",
      tags: ["FastAPI", "Celery", "Redis", "Next.js", "REST API", "LLM"],
      live: "#",
      github: "#"
    },
    {
      title: "React CMS & System Optimization",
      category: "Full-Stack Web Application",
      image: "img/project-5.png",
      description: "Restructured a Laravel backend to support a modern React-based CMS. Implemented secure user registration with OAuth-based authentication. Enhanced backend workflows and email notification services to ensure seamless communication with the frontend CMS.",
      tags: ["Laravel", "React", "OAuth", "CMS", "Full-Stack"],
      live: "#",
      github: "#"
    },
    {
      title: "Web Optimization & Core Web Vitals",
      category: "Performance Engineering",
      image: "img/project-6.png",
      description: "Optimized application performance for high-traffic sites, significantly improving Largest Contentful Paint (LCP) and Core Web Vitals scores. Implemented automated image optimization pipelines and asset minification to reduce server response times and enhance SEO.",
      tags: ["SEO", "Core Web Vitals", "Optimization", "Asset Minification", "Performance"],
      live: "#",
      github: "#"
    }
  ];

  return (
    <div className="min-h-screen bg-white">
      {/* Navigation Bar */}
      <nav className="sticky top-0 z-50 bg-white border-b border-slate-200">
        <div className="container mx-auto px-6 py-4">
          <button
            onClick={() => navigate('/')}
            className="flex items-center gap-2 text-primary hover:gap-3 transition-all font-semibold"
          >
            <ArrowLeft size={20} />
            <span>Back to Home</span>
          </button>
        </div>
      </nav>

      {/* Main Content */}
      <div className="container mx-auto px-6 py-20">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
        >
          {/* Header */}
          <div className="text-center mb-20">
            <span className="text-primary font-bold uppercase tracking-widest text-sm">Portfolio</span>
            <h1 className="text-5xl font-bold mt-4 mb-6">All Projects</h1>
            <p className="text-lg text-slate-600 max-w-2xl mx-auto">
              Explore my complete collection of projects showcasing expertise in full-stack development, AI/ML, and modern web technologies.
            </p>
            <div className="w-20 h-1.5 bg-primary mx-auto rounded-full mt-6"></div>
          </div>

          {/* Projects Grid */}
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-10">
            {projects.map((project, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, scale: 0.95 }}
                whileInView={{ opacity: 1, scale: 1 }}
                viewport={{ once: true }}
                transition={{ delay: index * 0.1 }}
                className="group bg-slate-50 rounded-3xl overflow-hidden shadow-lg hover:shadow-2xl border border-slate-200 transition-all"
              >
                <div className="relative h-72 overflow-hidden bg-slate-200">
                  <img
                    src={project.image}
                    alt={project.title}
                    className="w-full h-full object-contain group-hover:scale-110 transition-transform duration-500 p-4"
                  />
                  <div className="absolute inset-0 bg-primary/80 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-6">
                    {project.github !== "#" && (
                      <a
                        href={project.github}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="p-3 bg-white text-primary rounded-full hover:scale-110 transition-transform"
                      >
                        <Github size={24} />
                      </a>
                    )}
                  </div>
                </div>

                <div className="p-8">
                  <div className="flex items-center gap-2 text-primary text-xs font-bold mb-3">
                    <Layers size={14} />
                    {project.category}
                  </div>
                  <h3 className="text-xl font-bold mb-3">{project.title}</h3>
                  <p className="text-slate-600 mb-6 text-sm leading-relaxed">
                    {project.description}
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {project.tags.map((tag) => (
                      <span
                        key={tag}
                        className="text-[10px] font-bold tracking-wider px-3 py-1 bg-primary/10 text-primary rounded-lg"
                      >
                        {tag}
                      </span>
                    ))}
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </div>
    </div>
  );
};

export default AllProjects;
